import os
import sys
import re
import mysql.connector
from mysql.connector import Error

def prompt(msg):
    try:
        return input(msg).strip()
    except EOFError:
        return ""

def validate_file_path(path):
    if not path:
        raise ValueError("Empty file path")
    normalized = os.path.abspath(path)
    if not os.path.isfile(normalized):
        raise ValueError(f"File does not exist: {normalized}")
    if any(ch in path for ch in ["\x00", "\n", "\r"]):
        raise ValueError("Invalid characters in file path")
    return normalized

def validate_identifier(name, kind="identifier"):
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", name or ""):
        raise ValueError(f"Invalid {kind}: {name}")
    return name

def build_load_data_sql(table_name, columns):
    cols = ""
    if columns:
        validated = [validate_identifier(c, "column") for c in columns]
        cols = f" ({', '.join('`' + c + '`' for c in validated)})"
    sql = (
        f"LOAD DATA LOCAL INFILE %s "
        f"INTO TABLE `{table_name}` "
        f"FIELDS TERMINATED BY ',' "
        f'OPTIONALLY ENCLOSED BY \'"\' '
        f"LINES TERMINATED BY '\\n' "
        f"IGNORE 1 LINES"
        f"{cols}"
    )
    return sql

def main():
    host = prompt("MySQL host [localhost]: ") or "localhost"
    port_in = prompt("MySQL port [3306]: ") or "3306"
    user = prompt("MySQL user: ")
    password = prompt("MySQL password: ")
    database = prompt("MySQL database: ")
    table_name = validate_identifier(prompt("Target table: "), "table")
    file_path = validate_file_path(prompt("CSV file path: "))
    columns_in = prompt("Columns (comma-separated, optional): ")

    try:
        port = int(port_in)
    except ValueError:
        print("Invalid port", file=sys.stderr)
        sys.exit(1)

    columns = [c.strip() for c in columns_in.split(",") if c.strip()] if columns_in else []

    conn = None
    cursor = None
    try:
        conn = mysql.connector.connect(
            host=host,
            port=port,
            user=user,
            password=password,
            database=database,
            allow_local_infile=True,
        )
        cursor = conn.cursor()
        sql = build_load_data_sql(table_name, columns)
        cursor.execute(sql, (file_path,))
        conn.commit()
        print(f"Imported {cursor.rowcount} rows from {file_path} into {table_name}")
    except (Error, ValueError) as e:
        print(f"Import failed: {e}", file=sys.stderr)
        sys.exit(1)
    finally:
        if cursor is not None:
            cursor.close()
        if conn is not None and conn.is_connected():
            conn.close()

if __name__ == "__main__":
    main()